SELECT COUNT(*) AS followers_with_concert_growth
FROM follower_growth
WHERE growth_method = 'concerts';

SELECT MAX(growth_rate) AS max_growth_rate
FROM influencer_growth
WHERE year = 1990;

SELECT growth_rate
FROM influencer_growth
WHERE influencer_id = 0 AND year = 1980;

SELECT AVG(growth_rate) AS average_growth_rate
FROM follower_growth
WHERE year = 1980;

SELECT genre_id, COUNT(follower_id) AS follower_count
FROM follower_genres
GROUP BY genre_id;

SELECT comment_text
FROM influencer_comments
WHERE comment_engagement > 300;

SELECT comment_text
FROM follower_comments
WHERE comment_engagement = (SELECT MAX(comment_engagement) FROM follower_comments);

SELECT AVG(comment_engagement) AS avg_engagement
FROM (
    SELECT comment_engagement FROM influencer_comments WHERE comment_platform = 'Instagram'
    UNION ALL
    SELECT comment_engagement FROM follower_comments WHERE comment_platform = 'Instagram'
) AS combined_comments;

SELECT relationship_type, AVG(relationship_strength) AS avg_strength
FROM influencer_followers
GROUP BY relationship_type;
